#!/usr/bin/env node

/**
 * Input Component Implementation Validator - Enhanced Version
 *
 * ============================================================================
 * IMPORTANT: ONLY FOR CLAUDE-GENERATED FILES
 * ============================================================================
 *
 * This validator should ONLY be run on files that were NEWLY GENERATED BY CLAUDE.
 *
 * Purpose:
 *   - Verify that Claude-generated input components follow all guidelines
 *   - Catch guideline violations before they enter the codebase
 *   - Ensure consistent patterns in AI-generated form field components
 *
 * When to use:
 *   - After Claude generates a new input field component
 *   - After Claude creates a custom form field implementation
 *   - After Claude modifies MvsFormFieldBaseComponent extensions
 *
 * When NOT to use:
 *   - On existing legacy input components
 *   - On third-party or external code
 *   - On manually written code (unless verifying against guidelines)
 *
 * ============================================================================
 * AUTO-CORRECTION WORKFLOW
 * ============================================================================
 *
 * When this script reports errors on Claude-generated files:
 *
 * 1. CLAUDE MUST read the error messages carefully
 * 2. CLAUDE MUST fix each violation in the generated file
 * 3. CLAUDE MUST re-run this validation script
 * 4. REPEAT steps 1-3 until ALL checks pass (✅)
 *
 * Claude should NEVER leave a file with validation errors.
 * The auto-correction loop continues until zero errors remain.
 *
 * Example workflow:
 *   - Claude generates mvs-form-field-custom.component.ts
 *   - Run: node check-guidelines.js ./mvs-form-field-custom.component.ts
 *   - ERROR: "Missing super.ngOnInit() in ngOnInit()"
 *   - Claude fixes: adds super.ngOnInit() as first line
 *   - Run: node check-guidelines.js ./mvs-form-field-custom.component.ts
 *   - ✅ Validation PASSED
 *
 * ============================================================================
 *
 * Comprehensive validation for input field component implementations.
 * Validates ALL requirements from SKILL.md documentation.
 *
 * Validates:
 * 1. Component Structure
 *    - @Component() decorator
 *    - Extends MvsFormFieldBaseComponent
 *    - Correct selector pattern (mvs-form-field-*)
 *    - Implements OnInit, OnChanges, OnDestroy
 *
 * 2. Required Inputs
 *    - @Input() formGroup
 *    - @Input() formField
 *    - @Input() readOnly (optional)
 *    - @Input() disabled (optional)
 *
 * 3. Lifecycle Methods
 *    - ngOnInit() with super.ngOnInit()
 *    - ngOnChanges() with super.ngOnChanges()
 *    - ngOnDestroy() with super.ngOnDestroy()
 *
 * 4. Required Methods
 *    - refreshComponent()
 *    - handleFieldChange()
 *
 * 5. Required Patterns
 *    - this.initialized = true
 *    - this.onChange.emit()
 *    - formControlName binding
 *
 * Usage: node check-guidelines.js <path-to-component.ts>
 *
 * Exit Codes:
 *   0 = All validations passed
 *   1 = One or more validations failed
 */

const fs = require('fs');
const path = require('path');

// ANSI color codes for terminal output
const colors = {
  reset: '\x1b[0m',
  red: '\x1b[31m',
  green: '\x1b[32m',
  yellow: '\x1b[33m',
  blue: '\x1b[34m',
  cyan: '\x1b[36m',
  magenta: '\x1b[35m',
  dim: '\x1b[2m'
};

function print(message, color = 'reset') {
  console.log(`${colors[color]}${message}${colors.reset}`);
}

function printSection(title) {
  console.log();
  print(`▸ ${title}`, 'magenta');
  print('─'.repeat(50), 'dim');
}

// Validation results tracker
const results = {
  passed: [],
  failed: [],
  warnings: [],
  skipped: []
};

function pass(rule, detail = '') {
  results.passed.push({ rule, detail });
  const detailStr = detail ? ` ${colors.dim}(${detail})${colors.reset}` : '';
  print(`  ✓ ${rule}${detailStr}`, 'green');
}

function fail(rule, hint = '') {
  results.failed.push({ rule, hint });
  print(`  ✗ ${rule}`, 'red');
  if (hint) {
    print(`    └─ Hint: ${hint}`, 'yellow');
  }
}

function warn(message, hint = '') {
  results.warnings.push({ message, hint });
  print(`  ⚠ ${message}`, 'yellow');
  if (hint) {
    print(`    └─ ${hint}`, 'dim');
  }
}

function skip(rule, reason = '') {
  results.skipped.push({ rule, reason });
  print(`  ○ ${rule} ${colors.dim}(skipped: ${reason})${colors.reset}`, 'dim');
}

/**
 * Main validation function
 */
function validateInputComponent(filePath) {
  // Print header
  console.log();
  print('╔══════════════════════════════════════════════════════════════════════╗', 'cyan');
  print('║        Input Component Implementation Validator (Enhanced)           ║', 'cyan');
  print('║                    Coverage: 100% of SKILL.md                        ║', 'cyan');
  print('╚══════════════════════════════════════════════════════════════════════╝', 'cyan');

  // Check file exists
  if (!fs.existsSync(filePath)) {
    print(`\n✗ File not found: ${filePath}`, 'red');
    process.exit(1);
  }

  const content = fs.readFileSync(filePath, 'utf-8');
  const fileName = path.basename(filePath);

  print(`\nFile: ${fileName}`, 'blue');
  print(`Path: ${filePath}`, 'dim');

  // ═══════════════════════════════════════════════════════════════════════════
  // SECTION 1: Component Structure
  // ═══════════════════════════════════════════════════════════════════════════
  printSection('Component Structure');

  // 1.1 Check @Component() decorator
  const componentDecoratorPattern = /@Component\s*\(\s*\{/;
  if (componentDecoratorPattern.test(content)) {
    pass('@Component() decorator present');
  } else {
    fail(
      'Missing @Component() decorator',
      'Add @Component({ selector: "...", template: "..." }) above the class'
    );
  }

  // 1.2 Check extends MvsFormFieldBaseComponent
  const extendsPattern = /extends\s+MvsFormFieldBaseComponent/;
  if (extendsPattern.test(content)) {
    pass('Extends MvsFormFieldBaseComponent');
  } else {
    fail(
      'Component must extend MvsFormFieldBaseComponent',
      'Change class declaration to: export class YourComponent extends MvsFormFieldBaseComponent'
    );
  }

  // 1.3 Check selector pattern
  const selectorPattern = /selector:\s*['"]([^'"]+)['"]/;
  const selectorMatch = content.match(selectorPattern);
  if (selectorMatch) {
    const selector = selectorMatch[1];
    if (selector.startsWith('mvs-form-field-')) {
      pass(`Selector matches pattern`, selector);
    } else {
      fail(
        `Selector should start with 'mvs-form-field-'`,
        `Found: '${selector}'. Change to: 'mvs-form-field-[your-component-name]'`
      );
    }
  } else {
    fail('No selector found in @Component decorator');
  }

  // 1.4 Check implements interfaces
  const implementsPattern = /implements\s+([^{]+)/;
  const implementsMatch = content.match(implementsPattern);
  if (implementsMatch) {
    const interfaces = implementsMatch[1];
    const hasOnInit = /OnInit/.test(interfaces);
    const hasOnChanges = /OnChanges/.test(interfaces);
    const hasOnDestroy = /OnDestroy/.test(interfaces);

    if (hasOnInit && hasOnChanges && hasOnDestroy) {
      pass('Implements OnInit, OnChanges, OnDestroy');
    } else {
      const missing = [];
      if (!hasOnInit) missing.push('OnInit');
      if (!hasOnChanges) missing.push('OnChanges');
      if (!hasOnDestroy) missing.push('OnDestroy');
      warn(
        `Missing interface implementations: ${missing.join(', ')}`,
        'Add: implements OnInit, OnChanges, OnDestroy'
      );
    }
  } else {
    warn(
      'No implements clause found',
      'Consider adding: implements OnInit, OnChanges, OnDestroy'
    );
  }

  // ═══════════════════════════════════════════════════════════════════════════
  // SECTION 2: Required Inputs (inherited from base, but verify usage)
  // ═══════════════════════════════════════════════════════════════════════════
  printSection('Input Properties');

  // 2.1 Check formGroup usage
  const formGroupUsagePattern = /this\.formGroup|formGroup\./;
  if (formGroupUsagePattern.test(content)) {
    pass('Uses formGroup property');
  } else {
    warn(
      'No formGroup usage found',
      'Ensure you use this.formGroup to access the FormGroup'
    );
  }

  // 2.2 Check formField usage
  const formFieldUsagePattern = /this\.formField|formField\./;
  if (formFieldUsagePattern.test(content)) {
    pass('Uses formField property');
  } else {
    warn(
      'No formField usage found',
      'Ensure you use this.formField to access field metadata'
    );
  }

  // 2.3 Check readOnly handling
  const readOnlyPattern = /this\.readOnly|readOnly|readonly/i;
  if (readOnlyPattern.test(content)) {
    pass('Handles readOnly state');
  } else {
    warn(
      'No readOnly handling found',
      'Consider handling readOnly state for proper display'
    );
  }

  // 2.4 Check disabled handling
  const disabledPattern = /this\.disabled|disabled/;
  if (disabledPattern.test(content)) {
    pass('Handles disabled state');
  } else {
    warn(
      'No disabled handling found',
      'Consider handling disabled state for proper interaction'
    );
  }

  // ═══════════════════════════════════════════════════════════════════════════
  // SECTION 3: Lifecycle Methods
  // ═══════════════════════════════════════════════════════════════════════════
  printSection('Lifecycle Methods');

  // 3.1 Check ngOnInit with super call
  const ngOnInitPattern = /ngOnInit\s*\(\s*\)\s*[:{]/;
  const superNgOnInitPattern = /super\.ngOnInit\s*\(\s*\)/;
  if (ngOnInitPattern.test(content)) {
    if (superNgOnInitPattern.test(content)) {
      pass('ngOnInit() calls super.ngOnInit()');
    } else {
      fail(
        'Missing super.ngOnInit() in ngOnInit()',
        'Add super.ngOnInit() as the FIRST line in ngOnInit()'
      );
    }
  } else {
    skip('ngOnInit() method', 'base class handles initialization');
  }

  // 3.2 Check ngOnChanges with super call
  const ngOnChangesPattern = /ngOnChanges\s*\([^)]*\)\s*[:{]/;
  const superNgOnChangesPattern = /super\.ngOnChanges\s*\(/;
  if (ngOnChangesPattern.test(content)) {
    if (superNgOnChangesPattern.test(content)) {
      pass('ngOnChanges() calls super.ngOnChanges()');
    } else {
      fail(
        'Missing super.ngOnChanges() in ngOnChanges()',
        'Add super.ngOnChanges(changes) as the FIRST line in ngOnChanges()'
      );
    }
  } else {
    skip('ngOnChanges() method', 'base class handles change detection');
  }

  // 3.3 Check ngOnDestroy with super call
  const ngOnDestroyPattern = /ngOnDestroy\s*\(\s*\)\s*[:{]/;
  const superNgOnDestroyPattern = /super\.ngOnDestroy\s*\(\s*\)/;
  if (ngOnDestroyPattern.test(content)) {
    if (superNgOnDestroyPattern.test(content)) {
      pass('ngOnDestroy() calls super.ngOnDestroy()');
    } else {
      fail(
        'Missing super.ngOnDestroy() in ngOnDestroy()',
        'Add super.ngOnDestroy() as the LAST line in ngOnDestroy()'
      );
    }
  } else {
    skip('ngOnDestroy() method', 'base class handles cleanup');
  }

  // ═══════════════════════════════════════════════════════════════════════════
  // SECTION 4: Required Methods
  // ═══════════════════════════════════════════════════════════════════════════
  printSection('Required Methods');

  // 4.1 Check refreshComponent() method
  const refreshComponentPattern = /refreshComponent\s*\(\s*\)\s*[:{]/;
  if (refreshComponentPattern.test(content)) {
    pass('Implements refreshComponent() method');

    // Check if refreshComponent is called in ngOnInit
    const refreshInOnInitPattern = /ngOnInit[\s\S]*?this\.refreshComponent\s*\(\s*\)/;
    if (refreshInOnInitPattern.test(content)) {
      pass('refreshComponent() called in ngOnInit()');
    } else {
      warn(
        'refreshComponent() not called in ngOnInit()',
        'Consider calling this.refreshComponent() in ngOnInit()'
      );
    }
  } else {
    fail(
      'Missing refreshComponent() method',
      'Add: refreshComponent() { /* load configuration from formField */ }'
    );
  }

  // 4.2 Check handleFieldChange() method
  const handleFieldChangePattern = /handleFieldChange\s*\([^)]*\)\s*[:{]/;
  if (handleFieldChangePattern.test(content)) {
    pass('Implements handleFieldChange() method');
  } else {
    fail(
      'Missing handleFieldChange() method',
      'Add: handleFieldChange(event: any) { /* process value and emit change */ }'
    );
  }

  // ═══════════════════════════════════════════════════════════════════════════
  // SECTION 5: Required Patterns
  // ═══════════════════════════════════════════════════════════════════════════
  printSection('Required Patterns');

  // 5.1 Check initialized = true
  const initializedPattern = /this\.initialized\s*=\s*true/;
  if (initializedPattern.test(content)) {
    pass('Sets this.initialized = true');
  } else {
    fail(
      'Missing "this.initialized = true"',
      'Add this.initialized = true at the end of ngOnInit() after setup'
    );
  }

  // 5.2 Check onChange.emit() call
  const onChangeEmitPattern = /this\.onChange\.emit\s*\(/;
  if (onChangeEmitPattern.test(content)) {
    pass('Emits onChange event');

    // Check if emit is in handleFieldChange
    const emitInHandlerPattern = /handleFieldChange[\s\S]*?this\.onChange\.emit/;
    if (emitInHandlerPattern.test(content)) {
      pass('onChange.emit() in handleFieldChange()');
    } else {
      warn(
        'onChange.emit() not in handleFieldChange()',
        'Ensure onChange is emitted in handleFieldChange() method'
      );
    }
  } else {
    fail(
      'Missing this.onChange.emit() call',
      'Add this.onChange.emit(event) in handleFieldChange() to notify form of changes'
    );
  }

  // 5.3 Check FormControl binding pattern
  const formControlBindingPattern = /formControlName\s*[=:]\s*['"]?formField\.id|this\.formField\.id|\[formControlName\]/;
  const formControlSetValuePattern = /formGroup\.controls\[.*formField\.id.*\]\.setValue/;
  if (formControlBindingPattern.test(content) || formControlSetValuePattern.test(content)) {
    pass('Uses formField.id for FormControl binding');
  } else {
    warn(
      'FormControl binding pattern not found',
      'Use formControlName="formField.id" or this.formGroup.controls[this.formField.id]'
    );
  }

  // 5.4 Check for value processing in handleFieldChange
  const valueProcessingPattern = /handleFieldChange[\s\S]*?(\.value|\.trim\(\)|setValue)/;
  if (valueProcessingPattern.test(content)) {
    pass('Processes value in handleFieldChange()');
  } else {
    warn(
      'No value processing found in handleFieldChange()',
      'Consider processing/validating the value before emitting'
    );
  }

  // ═══════════════════════════════════════════════════════════════════════════
  // SECTION 6: Template Checks (if inline template)
  // ═══════════════════════════════════════════════════════════════════════════
  const inlineTemplatePattern = /template\s*:\s*`([^`]*)`/s;
  const inlineTemplateMatch = content.match(inlineTemplatePattern);

  if (inlineTemplateMatch) {
    printSection('Template Validation');
    const template = inlineTemplateMatch[1];

    // Check [formGroup] binding
    if (/\[formGroup\]/.test(template)) {
      pass('Template has [formGroup] binding');
    } else {
      warn('Template missing [formGroup] binding');
    }

    // Check formControlName or [formControlName]
    if (/formControlName|formControl/.test(template)) {
      pass('Template has formControlName binding');
    } else {
      warn('Template missing formControlName binding');
    }

    // Check change event binding
    if (/\(change\)|\(ngModelChange\)|\(onSelect\)|\(onClick\)/.test(template)) {
      pass('Template has change event binding');
    } else {
      warn('Template missing change event binding');
    }
  }

  // ═══════════════════════════════════════════════════════════════════════════
  // Print Summary
  // ═══════════════════════════════════════════════════════════════════════════
  console.log();
  print('═'.repeat(70), 'cyan');
  print('  VALIDATION SUMMARY', 'cyan');
  print('═'.repeat(70), 'cyan');
  console.log();

  const total = results.passed.length + results.failed.length;
  const passRate = total > 0 ? Math.round((results.passed.length / total) * 100) : 0;

  print(`  ✓ Passed:   ${results.passed.length}`, 'green');
  print(`  ✗ Failed:   ${results.failed.length}`, results.failed.length > 0 ? 'red' : 'green');
  print(`  ⚠ Warnings: ${results.warnings.length}`, results.warnings.length > 0 ? 'yellow' : 'green');
  print(`  ○ Skipped:  ${results.skipped.length}`, 'dim');
  console.log();
  print(`  Pass Rate:  ${passRate}%`, passRate === 100 ? 'green' : passRate >= 70 ? 'yellow' : 'red');

  console.log();
  print('═'.repeat(70), 'cyan');

  // Exit with appropriate code
  if (results.failed.length > 0) {
    console.log();
    print('❌ Validation FAILED - Please fix the errors above', 'red');
    console.log();
    process.exit(1);
  } else if (results.warnings.length > 0) {
    console.log();
    print('⚠️  Validation PASSED with warnings', 'yellow');
    console.log();
    process.exit(0);
  } else {
    console.log();
    print('✅ Validation PASSED - Component follows all guidelines!', 'green');
    console.log();
    process.exit(0);
  }
}

// ═══════════════════════════════════════════════════════════════════════════
// CLI Entry Point
// ═══════════════════════════════════════════════════════════════════════════

const filePath = process.argv[2];

if (!filePath) {
  console.log();
  print('Input Component Implementation Validator', 'cyan');
  print('─'.repeat(40), 'dim');
  console.log();
  print('Usage:', 'yellow');
  print('  node check-guidelines.js <path-to-component.ts>', 'reset');
  console.log();
  print('Example:', 'yellow');
  print('  node check-guidelines.js ./my-input.component.ts', 'reset');
  print('  node check-guidelines.js src/app/shared/form/field/text/text-field.component.ts', 'reset');
  console.log();
  process.exit(1);
}

// Resolve to absolute path and run validation
const absolutePath = path.resolve(filePath);
validateInputComponent(absolutePath);
